function parseQs(qs) {
  const out = {};
  if (!qs) return out;
  for (const part of String(qs).split('|')) {
    const i = part.indexOf('=');
    if (i === -1) continue;
    const k = part.slice(0, i);
    const v = part.slice(i + 1);
    out[k] = v;
  }
  return out;
}

const u = $json;


const cb = u.callback_query;
const msg = u.message || (cb && cb.message);

const chat_id = msg?.chat?.id ?? null;
const text = msg?.text ?? '';
const cb_data = cb?.data ?? '';

const parsed = parseQs(cb_data);

let kind = 'unknown';
let command = null;

if (cb) {
  kind = 'callback';
} else if (msg) {
  kind = 'message';
  if (typeof text === 'string' && text.startsWith('/')) {
  const firstToken = text.trim().split(/\s+/)[0].toLowerCase();
  command = firstToken.replace(/@[\w_]+$/, '');
}
}

return [{
  json: {
    kind,
    command,
    chat_id,
    message_id: msg?.message_id ?? null,
    from_id: msg?.from?.id ?? null,
    clicked_by: cb?.from?.id ?? null,
    callback_id: cb?.id ?? null,
    callback_data: cb_data,
    parsed,
    raw: u,

    TELEGRAM_BOT_TOKEN: u.TELEGRAM_BOT_TOKEN || '',
    PAGE_SIZE: u.PAGE_SIZE || 10,
    RECIPE_SLOTS: u.RECIPE_SLOTS || 5,
    INGREDIENT_PREVIEW_COUNT: u.INGREDIENT_PREVIEW_COUNT || 8,
    MAX_INSTRUCTION_STEPS: u.MAX_INSTRUCTION_STEPS || 30
  }
}];

