  return String(s || '').trim();
}

const out = [];

for (const item of $input.all()) {
  const j = item.json;

  const title = esc(j.title);
  const category = esc(j.category);
  const area = esc(j.area);
  const image = esc(j.image);
  const recipeId = esc(j.recipe_id);
  const source = esc(j.source);
  const ingredientsPreview = Array.isArray(j.ingredients_preview)
    ? j.ingredients_preview
    : [];

  const cycleId = `${Date.now()}_${recipeId}`;

  const lines = [];
  lines.push(`🍽 ${title}`);

  const meta = [category, area].filter(Boolean).join(' | ');
  if (meta) {
    lines.push(meta);
  }

if (ingredientsPreview.length) {
  lines.push('');
  lines.push('🛒 Ingredients:');

  for (const ing of ingredientsPreview) {
    lines.push(`• ${ing}`);
  }

  const totalIngredients = Array.isArray(j.raw_ingredients) ? j.raw_ingredients.length : ingredientsPreview.length;
  const hiddenCount = Math.max(0, totalIngredients - ingredientsPreview.length);

  if (hiddenCount > 0) {
    lines.push(`• +${hiddenCount} more`);
  }
}

  const text = lines.join('\n');

  out.push({
    json: {
      photo_url: image || null,
      text,
      reply_markup: {
        inline_keyboard: [
          [
            {
              text: '✅ Add to List',
              callback_data: `a=vote|d=y|s=${source}|c=${cycleId}|r=${recipeId}`
            },
            {
              text: '❌ Skip',
              callback_data: `a=vote|d=n|s=${source}|c=${cycleId}|r=${recipeId}`
            }
          ],
          [
            {
              text: '📖 Instructions',
              callback_data: `a=inst|s=${source}|r=${recipeId}`
            }
          ]
        ]
      }
    }
  });
}

return out;

