const pageSize = Number($('Parse Telegram Command').item.json.PAGE_SIZE || 10);
const cols = 2;
const rowsPerPage = Math.ceil(pageSize / cols);

const chat_id = $('Parse Telegram Command').item.json.chat_id;
const page = Math.max(1, Number($('Load Chat State').item.json.shopping_page || 1));
const total = Number($('Count Shopping List Items').item.json.total || 0);
const maxPage = Math.max(1, Math.ceil(total / pageSize));

const items = $('Load Shopping List Page')
  .all()
  .map(i => i.json)
  .filter(i => i && i.id !== undefined);

function fmtQty(q) {
  if (q === null || q === undefined) return '';
  const n = Number(q);
  if (Number.isNaN(n)) return '';
  return (Math.round(n * 100) / 100).toString();
}

function shortName(s, max = 18) {
  s = String(s || '').trim();
  if (!s) return 'Item';
  if (s.length <= max) return s;

  const cut = s.slice(0, max);
  const lastSpace = cut.lastIndexOf(' ');

  if (lastSpace > max * 0.6) {
    return cut.slice(0, lastSpace) + '…';
  }

  return cut + '…';
}

function label(it) {
  const qty = fmtQty(it.qty);
  const unit = (it.unit || '').trim();
  const right = [qty, unit].filter(Boolean).join(' ');
  return `${it.ingredient_name}${right ? ' — ' + right : ''}`;
}

if (items.length === 0) {
  return [{
    json: {
      chat_id,
      text: '🛒 Shopping List\n\n✅ All done. List is empty.',
      reply_markup: {
        inline_keyboard: [
          [
            { text: '🔄 Refresh', callback_data: 'a=r' },
          ],
        ],
      },
      page: 1,
      maxPage: 1,
      pageSize,
    }
  }];
}

const header = `🛒 Shopping List (Page ${page}/${maxPage})`;
const lines = items.map((it, i) => `${i + 1}. ${label(it)}`);
const text = header + '\n\n' + lines.join('\n');

const kb = [];
for (let r = 0; r < rowsPerPage; r++) {
  const row = [];
  for (let c = 0; c < cols; c++) {
    const idx = r * cols + c;
    const it = items[idx];
    if (!it) continue;

    const btnText = `${idx + 1}. ${shortName(it.ingredient_name, 18)}`;

    row.push({
      text: btnText,
      callback_data: `a=t|id=${it.id}`,
    });
  }
  if (row.length) kb.push(row);
}

const prevPage = Math.max(1, page - 1);
const nextPage = Math.min(maxPage, page + 1);

kb.push([
  { text: '⬅️', callback_data: `a=p|p=${prevPage}` },
  { text: '🔄 Refresh', callback_data: 'a=r' },
  { text: '➡️', callback_data: `a=p|p=${nextPage}` },
]);

return [{
  json: {
    chat_id,
    text,
    reply_markup: { inline_keyboard: kb },
    page,
    maxPage,
    pageSize,
  }
}];

