const meal = $json.meals?.[0];

if (!meal) {
  throw new Error('No recipe found from TheMealDB.');
}

const chatId = $('Parse Telegram Command').item.json.chat_id;
const out = [];

function normalizeSpaces(s) {
  return String(s || '')
    .replace(/\u00a0/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function parseNumber(str) {
  if (!str) return null;
  str = str.trim();

  const mixed = str.match(/^(\d+)\s+(\d+)\/(\d+)$/);
  if (mixed) {
    return Number(mixed[1]) + Number(mixed[2]) / Number(mixed[3]);
  }

  const frac = str.match(/^(\d+)\/(\d+)$/);
  if (frac) {
    return Number(frac[1]) / Number(frac[2]);
  }

  str = str.replace(',', '.');
  const num = Number(str);
  return Number.isFinite(num) ? num : null;
}

function normalizeIngredientName(name) {
  let n = normalizeSpaces(name).toLowerCase();

  // plural / einfache Vereinheitlichung
  n = n
    .replace(/^eggs$/, 'egg')
    .replace(/^tomatoes$/, 'tomato')
    .replace(/^potatoes$/, 'potato')
    .replace(/^onions$/, 'onion')
    .replace(/^shallots$/, 'shallot')
    .replace(/^carrots$/, 'carrot')
    .replace(/^limes$/, 'lime')
    .replace(/^lemons$/, 'lemon')
    .replace(/^cloves of garlic$/, 'garlic')
    .replace(/^garlic cloves$/, 'garlic')
    .replace(/^spring onions$/, 'spring onion')
    .replace(/^bay leaves$/, 'bay leaf')
    .replace(/^chilies$/, 'chilli')
    .replace(/^chillies$/, 'chilli')
    .replace(/^prawns$/, 'prawn')
    .replace(/^mushrooms$/, 'mushroom')
    .replace(/^peppers$/, 'pepper')
    .replace(/^beans$/, 'bean');

  return n;
}

function titleCaseFromKey(key) {
  return key
    .split(' ')
    .map(w => w ? w[0].toUpperCase() + w.slice(1) : w)
    .join(' ');
}

function parseMeasure(raw) {
  let s = normalizeSpaces(raw).toLowerCase();

  if (!s) {
    return { qty: null, unit: null, raw: '' };
  }

  s = s
    .replace(/½/g, '1/2')
    .replace(/¼/g, '1/4')
    .replace(/¾/g, '3/4');

  const m = s.match(/^(\d+(?:[.,]\d+)?(?:\s+\d+\/\d+)?|\d+\/\d+)\s*(.*)$/);
  if (!m) {
    return { qty: null, unit: raw || null, raw };
  }

  const qty = parseNumber(m[1]);
  let unitRaw = normalizeSpaces(m[2]);

  if (qty == null) {
    return { qty: null, unit: raw || null, raw };
  }

  const unitMap = [
    [/^(teaspoons?|tsp)$/i, { factor: 5, unit: 'ml' }],
    [/^(tablespoons?|tbsp)$/i, { factor: 15, unit: 'ml' }],
    [/^(cups?|cup)$/i, { factor: 240, unit: 'ml' }],
    [/^(milliliters?|millilitres?|ml)$/i, { factor: 1, unit: 'ml' }],
    [/^(liters?|litres?|l)$/i, { factor: 1000, unit: 'ml' }],
    [/^(fluid ounces?|fl oz)$/i, { factor: 29.5735, unit: 'ml' }],
    [/^(grams?|g)$/i, { factor: 1, unit: 'g' }],
    [/^(kilograms?|kg)$/i, { factor: 1000, unit: 'g' }],
    [/^(ounces?|oz)$/i, { factor: 28.3495, unit: 'g' }],
    [/^(pounds?|lbs?|lb)$/i, { factor: 453.592, unit: 'g' }],
  ];

  for (const [regex, conv] of unitMap) {
    if (regex.test(unitRaw)) {
      return {
        qty: Math.round(qty * conv.factor),
        unit: conv.unit,
        raw,
      };
    }
  }

  if (/^cloves?$/.test(unitRaw)) return { qty, unit: 'cloves', raw };
  if (/^bunch(es)?$/.test(unitRaw)) return { qty, unit: 'bunch', raw };
  if (/^leaves?$/.test(unitRaw)) return { qty, unit: 'leaves', raw };
  if (/^sprigs?$/.test(unitRaw)) return { qty, unit: 'sprig', raw };
  if (/^to serve$/.test(unitRaw)) return { qty, unit: 'to garnish', raw };
  if (/^can(s)?$/.test(unitRaw)) return { qty, unit: 'can', raw };
  if (/^pinch$/.test(unitRaw)) return { qty, unit: 'pinch', raw };
  if (/^handful$/.test(unitRaw)) return { qty, unit: 'handful', raw };
  if (/^large$/.test(unitRaw)) return { qty, unit: 'large', raw };
  if (/^small$/.test(unitRaw)) return { qty, unit: 'small', raw };

  return {
    qty,
    unit: unitRaw || null,
    raw,
  };
}

for (let i = 1; i <= 20; i++) {
  const ingredientRaw = normalizeSpaces(meal[`strIngredient${i}`]);
  const measureRaw = normalizeSpaces(meal[`strMeasure${i}`]);

  if (!ingredientRaw) continue;

  const ingredient_key = normalizeIngredientName(ingredientRaw);
  const ingredient_name = titleCaseFromKey(ingredient_key);
  const parsed = parseMeasure(measureRaw);

  out.push({
    json: {
      chat_id: chatId,
      ingredient_key,
      ingredient_name,
      qty: parsed.qty,
      unit: parsed.unit,
    }
  });
}

return out;

function clean(s) {
  return String(s || '').replace(/\s+/g, ' ').trim();
}

const inputItems = $input.all();
const out = [];

for (const item of inputItems) {
  const meals = item.json.meals || [];
  if (!meals.length) continue;

  const meal = meals[0];

  const recipeId = clean(meal.idMeal);
  const title = clean(meal.strMeal);
  const image = clean(meal.strMealThumb);
  const category = clean(meal.strCategory);
  const area = clean(meal.strArea);
  const instructions = clean(meal.strInstructions);

  const rawIngredients = [];
  for (let i = 1; i <= 20; i++) {
    const name = clean(meal[`strIngredient${i}`]);
    const measure = clean(meal[`strMeasure${i}`]);

    if (!name) continue;

    rawIngredients.push({
      name,
      measure,
    });
  }
  const previewCount = Number($('Parse Telegram Command').item.json.INGREDIENT_PREVIEW_COUNT || 8);
  const ingredientsPreview = rawIngredients
    .slice(0, previewCount)
    .map(x => x.measure ? `${x.name} (${x.measure})` : x.name);

  out.push({
    json: {
      source: 'tmdb',
      recipe_id: recipeId,
      title,
      category,
      area,
      image,
      instructions,
      ingredients_preview: ingredientsPreview,
      raw_ingredients: rawIngredients,
    }
  });
}

return out;

const meal = $json.meals?.[0];

if (!meal) {
  throw new Error('No recipe found for instructions.');
}

const chat_id = $('Parse Telegram Command').item.json.chat_id;
const title = String(meal.strMeal || 'Recipe').trim();
const instructions = String(meal.strInstructions || '').trim();
const maxSteps = Number($('Parse Telegram Command').item.json.MAX_INSTRUCTION_STEPS || 30);

function escapeHtml(str) {
  return String(str || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function escapeRegex(str) {
  return String(str || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function simplify(text) {
  return String(text || '')
    .replace(/^\s*step\s*\d+[:.)\-\s]*/i, '')
    .replace(/^\s*\d+[:.)\-\s]+/, '')
    .replace(/about /gi, '')
    .replace(/approximately /gi, '')
    .replace(/then /gi, '')
    .replace(/minutes?/gi, 'Min.')
    .replace(/tablespoons?/gi, 'tbsp')
    .replace(/teaspoons?/gi, 'tsp')
    .replace(/\s+/g, ' ')
    .trim();
}

function splitSteps(text) {
  const cleaned = String(text || '')
    .replace(/\r/g, '')
    .replace(/\n{2,}/g, '\n')
    .replace(/STEP\s*(\d+)/gi, '\nSTEP $1 ')
    .replace(/(\d+)\)\s*/g, '\n$1. ')
    .replace(/\n+/g, '\n')
    .trim();

  let parts = cleaned
    .split(/\n(?=STEP\s*\d+|\d+\.\s+|- )/i)
    .map(s => s.trim())
    .filter(Boolean);

  if (parts.length <= 1) {
    parts = cleaned
      .split(/(?<=\.)\s+(?=[A-Z])/)
      .map(s => s.trim())
      .filter(s => s.length > 8);
  }

  if (parts.length <= 1) {
    parts = cleaned
      .split(/\n/)
      .map(s => s.trim())
      .filter(s => s.length > 8);
  }

  return parts
    .map(s => simplify(s))
    .filter(s => s.length > 8);
}

const ingredientNames = [];
for (let i = 1; i <= 20; i++) {
  const name = String(meal[`strIngredient${i}`] || '').trim();
  if (name) ingredientNames.push(name);
}

function boldIngredients(text, names) {
  let out = escapeHtml(text);
  const sorted = [...names].sort((a, b) => b.length - a.length);

  for (const name of sorted) {
    const pattern = new RegExp(`\\b${escapeRegex(name)}\\b`, 'gi');
    out = out.replace(pattern, match => `<b>${escapeHtml(match)}</b>`);
  }

  return out;
}

let steps = splitSteps(instructions);

steps = steps.filter((step, idx, arr) => {
  if (idx === 0) return true;
  return step.toLowerCase() !== arr[idx - 1].toLowerCase();
});

steps = steps.slice(0, maxSteps);

let lines = [];
lines.push(`🍳 <b>${escapeHtml(title)}</b>`);
lines.push('');

if (steps.length) {
  steps.forEach((step, i) => {
    const bolded = boldIngredients(step, ingredientNames);
    lines.push(`${i + 1}. ${bolded}`);
  });
} else {
  lines.push(escapeHtml(instructions || 'No instructions available.'));
}

let text = lines.join('\n');

const maxLen = 3800;
const parts = [];

while (text.length > maxLen) {
  let slice = text.slice(0, maxLen);
  const lastBreak = slice.lastIndexOf('\n');

  if (lastBreak > 200) {
    slice = slice.slice(0, lastBreak);
  }

  parts.push(slice);
  text = text.slice(slice.length).trim();
}

